// 检测头部手势（用 ref 读写冷却/区间锁）————AI辅助生成：DeepSeek-V4，2026-4-25
const detectHeadGesture = useCallback((pose) => {
if (!pose) return;
const yaw = pose.yaw;
let gesture = null;
let currentZone = 'neutral';

if (yaw > 15) { gesture = 'home'; currentZone = 'zone1'; }
else if (yaw > 10 && yaw <= 15) { gesture = 'form'; currentZone = 'zone2'; }
else if (yaw < -15) { gesture = 'settings'; currentZone = 'zone3'; }
else if (yaw >= -15 && yaw < -10) { gesture = 'todo'; currentZone = 'zone4'; }

const isNod = pose.pitch < -10;

const currentTime = Date.now();
const timeSinceLastSwitch = currentTime - lastPageSwitchTimeRef.current;

const canTriggerSwitch =
  (lastTriggeredAngleZoneRef.current !== 'neutral' && currentZone === 'neutral') ||
  (lastTriggeredAngleZoneRef.current === 'neutral' && currentZone !== 'neutral');

if (gesture && !isHeadTiltDetectedRef.current && timeSinceLastSwitch > 2000 && canTriggerSwitch) {
  isHeadTiltDetectedRef.current = true; setIsHeadTiltDetected(true);
  lastPageSwitchTimeRef.current = currentTime; setLastPageSwitchTime(currentTime);
  lastTriggeredAngleZoneRef.current = currentZone; setLastTriggeredAngleZone(currentZone);

  if (handleHeadGestureRef.current) handleHeadGestureRef.current(gesture);

  setTimeout(() => { isHeadTiltDetectedRef.current = false; setIsHeadTiltDetected(false); }, 2000);
} else if (isNod && !isHeadTiltDetectedRef.current) {
  isHeadTiltDetectedRef.current = true; setIsHeadTiltDetected(true);

  if (handleHeadGestureRef.current) handleHeadGestureRef.current('nod');

  setTimeout(() => { isHeadTiltDetectedRef.current = false; setIsHeadTiltDetected(false); }, 500);
} else if (currentZone === 'neutral' && lastTriggeredAngleZoneRef.current !== 'neutral') {
  lastTriggeredAngleZoneRef.current = 'neutral'; setLastTriggeredAngleZone('neutral');
}
}, []);

// 保存最新 detectHeadGesture 到 ref
