// 初始化眼动追踪 WebGazer————AI辅助生成：DeepSeek-V4，2026-4-25
useEffect(() => {
let isMounted = true;
const initWebgazer = async () => {
try {
const stream = await navigator.mediaDevices.getUserMedia({ video: true });
stream.getTracks().forEach(track => track.stop());
    const module = await import('webgazer');
    window.webgazer = module.default;

    await window.webgazer.setRegression('ridge')
      .setTracker('clmtrackr')
      .begin();
    
    window.webgazer.showVideoPreview(true)
      .showPredictionPoints(true)
      .applyKalmanFilter(true);

    window.webgazer.setGazeListener((data) => {
      if (data && isMounted) {
        webgazerRef.current = { x: data.x, y: data.y };
        if (checkGazeTargetRef.current) {
          checkGazeTargetRef.current(data.x, data.y); // 使用最新的函数
        }
      }
    });

    if (isMounted) {
      setWebgazerLoaded(true);
      console.log('WebGazer 初始化成功');
    }
  } catch (error) {
    console.error('WebGazer 初始化失败:', error);
    if (isMounted) {
      setWebgazerLoaded(false);
    }
  }
};

if (isMounted) {
  initWebgazer();
}

return () => {
  isMounted = false;
  if (window.webgazer) {
    window.webgazer.end();
  }
};
}, []);

// 语音识别初始化（全局命令）
useEffect(() => {
const handleSpeechResult = (event) => {
const results = Array.from(event.results);
const finalResults = results.filter(result => result.isFinal);
  if (finalResults.length > 0) {
    const lastResult = finalResults[finalResults.length - 1];
    const text = lastResult[0].transcript.toLowerCase();

    if (text !== lastProcessedText) {
      setTranscript(text);
      setLastProcessedText(text);

      if (currentPage === 'form') {
        if (text.includes("姓名")) {
          handleInputFocus('name');
          return;
        } else if (text.includes("邮箱")) {
          handleInputFocus('email');
          return;
        } else if (text.includes("消息")) {
          handleInputFocus('message');
          return;
        } else if (text.includes("主题")) {
          handleInputFocus('theme');
          return;
        }
      }

      if (text.includes("确认") && !confirmationLock.current) {
        confirmationLock.current = true;
        handleInteractionConfirm();
        setTimeout(() => { confirmationLock.current = false; }, 1000);
      }
    }
  }
};

const recognizer = createSpeechRecognition(handleSpeechResult);
if (recognizer) {
  speechRecognitionRef.current = recognizer;
  setRecognition(recognizer);
}
}, [lastProcessedText, handleInteractionConfirm, currentPage, createSpeechRecognition]);

// Face Mesh 初始化————AI辅助生成：DeepSeek-V4，2026-4-25
useEffect(() => {
let camera;
const faceMesh = new FaceMesh({
  locateFile: (file) => `https://cdn.jsdelivr.net/npm/@mediapipe/face_mesh/${file}`
});
faceMesh.setOptions({
  maxNumFaces: 1,
  refineLandmarks: true,
  minDetectionConfidence: 0.5,
  minTrackingConfidence: 0.5
});

faceMesh.onResults((results) => {
  if (!results.multiFaceLandmarks?.[0]) return;
  
  const landmarks = results.multiFaceLandmarks[0];
  if (landmarks && Array.isArray(landmarks)) {
    drawFaceLandmarks(landmarks);
    const pose = calculateHeadPose(landmarks);
    if (pose) {
      setHeadPose(pose);
      if (detectHeadGestureRef.current) {
        detectHeadGestureRef.current(pose); // 使用最新的检测逻辑
      }
    }
  }
});

const initCamera = async () => {
  camera = new Camera(videoRef.current, {
    onFrame: async () => {
      await faceMesh.send({ image: videoRef.current });
    },
    width: 640,
    height: 480
  });
  await camera.start();
};

initCamera();
return () => {
  camera?.stop();
  faceMesh?.close();
};
}, []);

const toggleListening = () => {
if (isListening) {
speechRecognitionRef.current?.stop();
} else {
speechRecognitionRef.current?.start();
}
setIsListening(!isListening);
};

const drawFaceLandmarks = (landmarks) => {
if (!landmarks || !canvasRef.current) return;
const canvas = canvasRef.current;
const ctx = canvas.getContext('2d');
ctx.clearRect(0, 0, canvas.width, canvas.height);

landmarks.forEach((landmark) => {
  if (!landmark?.x || !landmark?.y) return;
  const x = landmark.x * canvas.width;
  const y = landmark.y * canvas.height;
  
  ctx.beginPath();
  ctx.arc(x, y, 1, 0, 2 * Math.PI);
  ctx.fillStyle = '#FF0000';
  ctx.fill();
});
};

